    if isinstance(v, str):
        with open(v,'r') as f:
            return json.load(f)
    return v

business_records = load_var(var_call_2zESRXQokhF5Lf5iMBJbnpbn)
review_records = load_var(var_call_iTkaQoBL33XRjP3WrF6keht3)

